diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..9bc7e7922678 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -441,6 +441,20 @@ Instruction *InstCombinerImpl::foldSelectOpOp(SelectInst &SI, Instruction *TI,
     }
   }

+  // select c2, (select c1, X, Y), (select c1, Y, X) -> select (xor c1, c2), Y, X
+  if (auto *TIS = dyn_cast<SelectInst>(TI))
+    if (auto *FIS = dyn_cast<SelectInst>(FI))
+      if (TIS->getCondition() == FIS->getCondition() &&
+          TIS->getTrueValue() == FIS->getFalseValue() &&
+          TIS->getFalseValue() == FIS->getTrueValue() &&
+          TIS->getCondition()->getType() == SI.getCondition()->getType() &&
+          (TI->hasOneUse() && FI->hasOneUse())) {
+        Value *XorCond = Builder.CreateXor(TIS->getCondition(),
+                                           SI.getCondition());
+        return SelectInst::Create(XorCond, FIS->getTrueValue(),
+                                  TIS->getTrueValue());
+      }
+
   // Only handle binary operators (including two-operand getelementptr) with
   // one-use here. As with the cast case above, it may be possible to relax the
   // one-use constraint, but that needs be examined carefully since it may not

log.source_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %sel1 = select i1 %c1, i32 %a, i32 %b
  %sel2 = select i1 %c1, i32 %b, i32 %a
  %ret = select i1 %c2, i32 %sel1, i32 %sel2
  ret i32 %ret
}

